// client/hooks/useSort.ts
import { useQueryParam } from './useQueryParam';
import { SortSchema } from '@shared/schemas/sort';
import { z } from 'zod';
export function useSort() {
  const [s, setS] = useQueryParam('sort', z.string().regex(/^[a-z]+:(asc|desc)$/));
  const parsed = s ? SortSchema.parse({ field: s.split(':')[0], direction: s.split(':')[1] }) : { field: 'createdAt', direction: 'desc' };
  const setSort = (field: string, direction: 'asc'|'desc') => setS(`${field}:${direction}`);
  return [parsed, setSort] as const;
}

// client/components/SortableHeader.tsx
export function SortableHeader({ field, label }: { field: string; label: string }) {
  const [sort, setSort] = useSort();
  const active = sort.field === field;
  return <button onClick={() => setSort(field, active && sort.direction === 'desc' ? 'asc' : 'desc')}>{label} {active && (sort.direction === 'desc' ? '↓' : '↑')}</button>;
}

