// server/services/promoService.ts
export const promoService = {
  async validate(code: string) {
    const promo = await PromoCodeModel.findOne({ code, expiresAt: { $gt: new Date() } });
    if (!promo) throw new NotFoundError('Invalid code');
    if (promo.redemptions >= promo.maxRedemptions) throw new ConflictError('Code limit reached');
    return promo;
  },
  async redeem(code: string, tenantId: string) {
    const updated = await PromoCodeModel.findOneAndUpdate(
      { code, redemptions: { $lt: '$maxRedemptions' }, expiresAt: { $gt: new Date() }, redeemedBy: { $ne: tenantId } },
      { $inc: { redemptions: 1 }, $push: { redeemedBy: tenantId } },
      { new: true }
    );
    if (!updated) throw new ConflictError('Cannot redeem');
    await stripe.customers.update(tenantId, { coupon: updated.stripeCoupon });
    return updated;
  }
};

// server/services/verificationService.ts
const COOLDOWN_MS = 60_000;
const MAX_PER_DAY = 5;
export const verificationService = {
  async resend(userId: string) {
    const recent = await VerificationModel.findOne({ userId }).sort({ createdAt: -1 });
    if (recent && Date.now() - recent.createdAt.getTime() < COOLDOWN_MS) {
      throw new RateLimitError('Too soon', { meta: { retryAfter: Math.ceil((COOLDOWN_MS - (Date.now() - recent.createdAt.getTime())) / 1000) } });
    }
    const todayCount = await VerificationModel.countDocuments({ userId, createdAt: { $gte: startOfDay() } });
    if (todayCount >= MAX_PER_DAY) throw new RateLimitError('Daily limit', { meta: { retryAfter: 86400 } });
    const token = crypto.randomBytes(32).toString('hex');
    await VerificationModel.create({ userId, token, expiresAt: new Date(Date.now() + 24*3600*1000) });
    await emailJob.send({ to: (await userDal.byId(userId)).email, template: 'verify', token });
  }
};

