export async function dailySummary() {
  const lastRun = await JobRunModel.findOne({ job: 'daily_summary' }).sort({ ranAt: -1 });
  const now = new Date();
  const lastTime = lastRun?.ranAt ?? new Date(now.getTime() - 86400000);
  const daysMissed = Math.floor((now.getTime() - lastTime.getTime()) / 86400000) - 1;
  if (daysMissed > 0) {
    logger.warn({ daysMissed }, 'daily_summary_missed_runs');
    await emailJob.send({ template: 'summary_catchup', daysMissed });
  }
  await runSummary();
  await JobRunModel.create({ job: 'daily_summary', ranAt: now });
}

// server/services/crudFactory.ts
import { Model, Document } from 'mongoose';
import { ZodSchema } from 'zod';
import { tenantContext } from '../context/tenantContext';
import { NotFoundError } from '../errors';
export function createCrudService<T extends Document>(model: Model<T>, schema: ZodSchema<any>) {
  return {
    async list() { return model.find({ tenantId: tenantContext.requireTenant() }).lean(); },
    async byId(id: string) { const r = await model.findOne({ _id: id, tenantId: tenantContext.requireTenant() }).lean(); if (!r) throw new NotFoundError(); return r; },
    async create(input: unknown) { const parsed = schema.parse(input); return model.create({ ...parsed, tenantId: tenantContext.requireTenant() }); },
    async update(id: string, input: unknown) { const parsed = schema.partial().parse(input); const r = await model.findOneAndUpdate({ _id: id, tenantId: tenantContext.requireTenant() }, parsed, { new: true }).lean(); if (!r) throw new NotFoundError(); return r; },
    async remove(id: string) { const r = await model.deleteOne({ _id: id, tenantId: tenantContext.requireTenant() }); if (r.deletedCount === 0) throw new NotFoundError(); }
  };
}
export const tagsService = createCrudService(TagModel, TagSchema);

