// server/middleware/webhookVerify.ts
import { createHmac, timingSafeEqual } from 'crypto';
import { WebhookSecretModel } from '../models/WebhookSecret';
export async function verifySignature(sig: string, body: string) {
  const secrets = await WebhookSecretModel.find({ status: 'active' });
  for (const s of secrets) {
    const expected = createHmac('sha256', s.value).update(body).digest('hex');
    if (timingSafeEqual(Buffer.from(expected), Buffer.from(sig))) {
      logger.info({ secretId: s._id }, 'webhook_verified');
      return true;
    }
  }
  return false;
}

